import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
// import MoveForward from "@components/common/move-forward";
import Seo from "@components/seo";
import PortfolioTwo from "@screens/portfolio/index-portfolio";
import { useLocation } from "@reach/router";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const PortfolioPage = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Clone Scripts", link: null },
  ];
  const { data } = props;
  const location = useLocation();

  const fileUrl =
    data?.cloneScriptImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;
  const validData = data?.allMetaJson?.nodes[0];

  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "A clone script is a ready-to-use software and is an imitation of other popular sites allowing easy launching with customized features and expandability.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1222",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What is a Clone Script?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A Clone Script is a ready-made software, which duplicates the main functionality of a well-known platform, which enables business to start a similar site or application, with the possibility to customize it.",
            },
          },
          {
            "@type": "Question",
            name: "What industries can this clone script be used for?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "The cryptocurrency and eCommerce as well as matrimony, ride-hailing, food delivery, real estate, social networking, fintech, education, and on-demand service industries are only examples of industries in which clone scripts can be utilized.",
            },
          },
          {
            "@type": "Question",
            name: "Is making a clone illegal?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "It is not an illegal act to make a clone.It is however illegal to replicate a brand name, logo, copyrighted code, patented features, or trademarked elements of a platform without its consent. A legal clone script must imitate the simply not guarded intellectual property as the business model or the core functionality.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      />
      <BreadCrumbV2 items={breadcrumbLinks} />
      <PortfolioTwo db={db} />
      {/* <MoveForward db={db} /> */}
    </Layout_v2>
  );
};

export default PortfolioPage;

export const queryData = graphql`
  query MyQuery {
    cloneScriptImg: file(relativePath: { eq: "clone-script.png" }) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "clone-script" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
